private IneqTree Balls(double r)
{
	var res = new IneqTree();	

  	var pol = Ineq3DOnline.PlatonicSolids.Polyhedron.CreateDodecahedron(1.0);
  
  	foreach (var v in pol.Vertices)
    {
		//res = res | Ball(v.X, v.Y, v.Z, 1.5 * r);      
    }
  
  	foreach (var e in pol.Edges/*.Take(2)*/)
    {
		var v1 = pol.Vertices[e.Item1];
      	var v2 = pol.Vertices[e.Item2];
      	res = res | TorusPath(v1.X, v1.Y, v1.Z, v2.X, v2.Y, v2.Z, r);
    }
  
    foreach (var face in pol.Faces)
    {
      var vx = face.Sum(i => pol.Vertices[i].X) / face.Length;
      var vy = face.Sum(i => pol.Vertices[i].Y) / face.Length;
      var vz = face.Sum(i => pol.Vertices[i].Z) / face.Length;
      
      var rr = sqrt(vx*vx +vy*vy +vz*vz);
      vx /= rr;
      vy /= rr;
      vz /= rr;
      
      //res = res | Ball(vx, vy, vz,  1.5 * r);      
      
      foreach (var i in face)
      {
	      	res = res | TorusPath(vx, vy, vz, pol.Vertices[i].X, pol.Vertices[i].Y, pol.Vertices[i].Z, r);
      }
    } 
  
   	return res.ToFunc(0.008);
}

